import axios from 'axios';
import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { buildApiUrl } from '../utils/api';
import { clearStoredUser, isAdminUser, setStoredUser } from '../utils/auth';

const SIGNIN_URL = buildApiUrl('/signin');
const SUBMITTING_MESSAGE = 'Please wait while we authenticate your account.';

function Signin() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  async function handleSubmit(event) {
    event.preventDefault();

    const normalizedEmail = email.trim();

    setError('');

    if (!normalizedEmail || !password) {
      setError('Email and password are required.');
      return;
    }

    setIsSubmitting(true);

    try {
      const response = await axios.post(
        SIGNIN_URL,
        {
          email: normalizedEmail,
          password,
        },
        {
          withCredentials: true,
        },
      );

      const user = response.data?.user;

      if (!user) {
        clearStoredUser();
        setError('Login failed. Please try again.');
        return;
      }

      setStoredUser(user);
      navigate(isAdminUser(user) ? '/admin' : '/');
    } catch (requestError) {
      clearStoredUser();

      if (requestError.response?.data?.message) {
        setError(requestError.response.data.message);
      } else if (requestError.request) {
        setError('Could not connect to the sign-in service. Please try again.');
      } else {
        setError('Oops, something went wrong. Try again...');
      }
    } finally {
      setIsSubmitting(false);
    }
  }

  return (
    <section className="auth-page auth-page--signin">
      <div className="auth-shell">
        <div className="auth-shell__panel">
          <p className="auth-shell__eyebrow">Welcome Back</p>
          <h1>Sign in and continue your stay with ease.</h1>
          <p className="auth-shell__lead">
            Access your bookings, room choices, and dining plans from one smooth account
            experience.
          </p>

          <div className="auth-shell__highlights">
            <span>Fast sign in</span>
            <span>Booking access</span>
            <span>Secure checkout</span>
          </div>
        </div>

        <div className="auth-card">
          <div className="auth-card__header">
            <p className="auth-card__eyebrow">Account Access</p>
            <h2>Sign In</h2>
            <p>Enter your details below to continue.</p>
          </div>

          {isSubmitting && <div className="auth-alert auth-alert--info">{SUBMITTING_MESSAGE}</div>}
          {error && <div className="auth-alert auth-alert--error">{error}</div>}

          <form className="auth-form auth-form--signin" onSubmit={handleSubmit}>
            <label className="auth-field auth-field--signin">
              <span>Email Address</span>
              <input
                type="email"
                placeholder="Enter your email"
                required
                autoComplete="email"
                value={email}
                onChange={(event) => setEmail(event.target.value)}
              />
            </label>

            <label className="auth-field auth-field--signin">
              <span>Password</span>
              <div className="auth-password">
                <input
                  type={showPassword ? 'text' : 'password'}
                  placeholder="Enter your password"
                  required
                  autoComplete="current-password"
                  value={password}
                  onChange={(event) => setPassword(event.target.value)}
                />
                <button
                  type="button"
                  className="auth-password__toggle"
                  onClick={() => setShowPassword((current) => !current)}
                  aria-label={showPassword ? 'Hide password' : 'Show password'}
                  aria-pressed={showPassword}
                >
                  {showPassword ? 'Hide' : 'Show'}
                </button>
              </div>
            </label>

            <button type="submit" className="auth-submit" disabled={isSubmitting}>
              {isSubmitting ? 'Signing In...' : 'Sign In'}
            </button>

            <p className="auth-switch">
              Don&apos;t have an account? <Link to="/signup">Register</Link>
            </p>
          </form>
        </div>
      </div>
    </section>
  );
}

export default Signin;
